export type MatchStatus = 'LIKELY_ELIGIBLE' | 'REVIEW_REQUIRED' | 'EXCLUDED';
export type CriterionType = 'include' | 'exclude_warn';

export interface EligibilityCriterion {
  criterion: string;
  pass: boolean | null;   // null = data unavailable, needs manual review
  value: string;
  type: CriterionType;
}

export interface TrialMatchResult {
  score: number;          // 0–100 match score
  status: MatchStatus;
  criteria: EligibilityCriterion[];
}

export interface TrialMatcherPatient {
  patientId: string;
  age: number;
  sex: string;
  cancerType: string;
  biomarkers: {
    kras: string;
    egfr: string;
    braf: string;
    her2: string;
    msi: string;
  };
  labs: {
    ast: number;
    alt: number;
    creatinine: number;
    hemoglobin: number;
    platelets: number;
    wbc: number;
  };
  priorTreatments: string[];
  lastVisit: string;
  trialMatches: Record<string, TrialMatchResult>;
  bestMatch: {
    trialId: string;
    score: number;
    status: MatchStatus;
  };
}

export interface TrialDefinition {
  nctId: string;
  name: string;
  shortName: string;
  sponsor: string;
  phase: string;
  route: string;
  indication: string;
  drug: string;
  status: 'Recruiting' | 'Active' | 'Completed';
  biomarker: string;
  color: string;
  colorLight: string;
  colorDark: string;
}

